# TypeDefs
class ProductType(Type):
    _type_name = "Product"

    id = String()
    name = String()
    price = Float()
    description = String()
    category_id = String()

    images = List(ImageType())

    @field
    def reviews(self, info: StrawberryInfo) -> t.List["Review"]:
        session = Session()
        return session.query(Review).filter_by(product_id=self.id)

class CategoryType(Type):
    _type_name = "Category"

    id = String()
